using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<TicketModelTrainer>();

var app = builder.Build();

// Train the model at startup so the pool can load it
var trainer = app.Services.GetRequiredService<TicketModelTrainer>();
trainer.TrainAndEvaluate();

// Register the pooled prediction engine (thread-safe for ASP.NET Core)
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainer.ModelPath);

// Rebuild the service provider to include the prediction pool
app = builder.Build();
app.MapControllers();
app.Run();

